INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (142491, 406158, 8, 'DrorLeibov', 'Spider-Man is a mainstream superhero origin story with the same comic-book appeal and outsider-hero energy that can attract a Hellboy viewer.', NULL);
