INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (335835, 185628, 8, 'DrorLeibov', 'Top Gun and The Last Samurai both use Tom Cruise as a charismatic lead in stories about discipline, honor, and proving oneself within a demanding culture.', NULL);
