INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (326155, 177369, 9, 'DrorLeibov', 'Taxi Driver and The King of Comedy are both Scorsese-De Niro character studies about alienated men whose obsession with fame or recognition becomes disturbing.', NULL);
