INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (139657, 149287, 8, 'DrorLeibov', 'Both are family-friendly adventure stories with a strong sense of wonder — Toy Story and Hook both treat childhood imagination as something real and worth protecting, making Hook a natural follow-up for fans of the magical Hogwarts world.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (149287, 159172, 9, 'DrorLeibov', 'Hook and Indiana Jones and the Last Crusade share a father-son emotional core wrapped inside a high-energy adventure — both films understand that the real treasure is the relationship, not the object being chased.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (235062, 130953, 8, 'DrorLeibov', 'North by Northwest and Goldfinger are both classics of the spy-thriller genre built around a charming hero outrunning dangerous adversaries with wit and confidence — Cary Grant and Sean Connery define the same archetype a decade apart.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (333856, 159172, 8, 'DrorLeibov', 'Titanic and Indiana Jones and the Last Crusade are both epic adventures where the emotional stakes — love and family — matter more than the physical danger, and both films earn their climaxes through genuine feeling rather than spectacle alone.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (337166, 393012, 2, 'DrorLeibov', 'Though both are family-friendly titles, Iron Man 1966 is a poor recommendation after Toy Story because its dated animation and episodic television format cannot match the emotional depth and visual invention Pixar achieved.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (176711, 383395, 2, 'DrorLeibov', 'Though both involve combat and costumed heroes, Captain America 1966 is a bad recommendation after Kill Bill Vol. 1 because it lacks any of the choreographic craft, visual style, or narrative tension that makes Tarantino exciting.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (131780, 397121, 2, 'DrorLeibov', 'Though both involve crime and danger, Matrix 1993 is a poor recommendation after Goodfellas because it has none of the authentic world-building, dark energy, or performance depth that makes Scorsese compelling.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (326155, 170721, 2, 'DrorLeibov', 'Though both were produced within decades of each other, The Jungle Book 2 is a bad recommendation after Taxi Driver because its lightweight animated tone has nothing in common with Scorsese and De Niro exploring urban alienation and violence.', NULL);